"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";
import {
  Activity,
  ArrowRight,
  CheckCircle2,
  Eye,
  EyeOff,
  Lock,
  Mail,
  ShieldCheck,
  Stethoscope,
  UserRound,
  Settings2,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { authService } from "@/services/authService";
import { useAuthStore } from "@/store";
import { UserRole } from "@/types";
import { cn } from "@/lib/utils";

export default function SignInPage() {
  const router = useRouter();
  const { toast } = useToast();
  const { user, setUser } = useAuthStore();

  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  useEffect(() => {
    if (!user) return;
    switch (user.role) {
      case "doctor":
        router.replace("/doctor");
        break;
      case "admin":
        router.replace("/admin");
        break;
      default:
        router.replace("/patient");
    }
  }, [router, user]);

  const handleLogin = async (event: React.FormEvent) => {
    event.preventDefault();
    setIsLoading(true);

    try {
      const response = await authService.login({ email, password });
      if (response.success && response.data) {
        setUser(response.data);
        toast({
          title: "Welcome back!",
          description: `Logged in as ${response.data.name}`,
        });

        switch (response.data.role) {
          case "doctor":
            router.push("/doctor");
            break;
          case "admin":
            router.push("/admin");
            break;
          default:
            router.push("/patient");
        }
      } else {
        toast({
          title: "Login failed",
          description: response.error || "Invalid credentials",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Error",
        description: "Something went wrong. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDemoLogin = async (role: UserRole) => {
    setIsLoading(true);

    try {
      const response = await authService.loginAsRole(role);
      if (response.success && response.data) {
        setUser(response.data);
        toast({
          title: "Demo Login",
          description: `Logged in as demo ${role}`,
        });

        switch (role) {
          case "doctor":
            router.push("/doctor");
            break;
          case "admin":
            router.push("/admin");
            break;
          default:
            router.push("/patient");
        }
      }
    } catch {
      toast({
        title: "Error",
        description: "Something went wrong",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const demoRoles: { role: UserRole; label: string; icon: React.ReactNode; description: string }[] = [
    {
      role: "patient",
      label: "Patient",
      icon: <UserRound className="h-4 w-4" />,
      description: "Book & manage appointments",
    },
    {
      role: "doctor",
      label: "Doctor",
      icon: <Stethoscope className="h-4 w-4" />,
      description: "View your schedule & patients",
    },
    {
      role: "admin",
      label: "Admin",
      icon: <Settings2 className="h-4 w-4" />,
      description: "Manage the platform",
    },
  ];

  return (
    <div className="min-h-screen bg-background flex">

      {/* ── LEFT PANEL ── */}
      <div className="hidden lg:flex lg:w-1/2 gradient-hero flex-col p-12 justify-between relative overflow-hidden">
        {/* Decorative blobs */}
        <div className="absolute -top-24 -left-24 w-96 h-96 rounded-full bg-white/5 blur-3xl pointer-events-none" />
        <div className="absolute bottom-0 right-0 w-80 h-80 rounded-full bg-white/5 blur-2xl pointer-events-none" />

        {/* Logo */}
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="flex items-center gap-3"
        >
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/20 backdrop-blur">
            <Activity className="h-5 w-5 text-white" />
          </div>
          <span className="text-xl font-bold text-white tracking-tight">CareConnect</span>
        </motion.div>

        {/* Hero copy */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.1 }}
          className="relative space-y-6"
        >
          <h1 className="text-4xl font-bold text-white leading-tight">
            Healthcare,<br />made simple.
          </h1>
          <p className="text-white/70 text-base leading-relaxed max-w-xs">
            Book appointments, consult with trusted doctors, and manage your health — all in one place.
          </p>

          {/* Feature pills */}
          <div className="flex flex-col gap-3 pt-2">
            {[
              { icon: <CheckCircle2 className="h-4 w-4" />, label: "Instant appointment booking" },
              { icon: <ShieldCheck className="h-4 w-4" />, label: "Verified doctors & specialists" },
              { icon: <CheckCircle2 className="h-4 w-4" />, label: "Medicine delivered to your door" },
            ].map((feat) => (
              <div key={feat.label} className="flex items-center gap-3">
                <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-white/15 text-white shrink-0">
                  {feat.icon}
                </div>
                <span className="text-sm text-white/85">{feat.label}</span>
              </div>
            ))}
          </div>
        </motion.div>

        {/* Footer */}
        <p className="text-white/40 text-xs">
          © {new Date().getFullYear()} CareConnect. All rights reserved.
        </p>
      </div>

      {/* ── RIGHT PANEL ── */}
      <div className="lg:w-1/2 flex-1 flex flex-col items-center justify-center overflow-y-auto py-10 px-5 sm:px-10">

        {/* Mobile logo */}
        <div className="flex items-center gap-2 mb-8 lg:hidden">
          <div className="flex h-9 w-9 items-center justify-center rounded-lg gradient-primary">
            <Activity className="h-5 w-5 text-primary-foreground" />
          </div>
          <span className="text-xl font-bold text-foreground">CareConnect</span>
        </div>

        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="w-full max-w-md"
        >
          {/* Header */}
          <div className="mb-7">
            <h2 className="text-2xl font-bold text-foreground tracking-tight">Welcome back</h2>
            <p className="text-sm text-muted-foreground mt-1">
              Don&apos;t have an account?{" "}
              <Link href="/signup" className="text-primary font-medium hover:underline">
                Sign up
              </Link>
            </p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">

            {/* ── Credentials Section ── */}
            <div className="rounded-xl border bg-card p-5 space-y-4">
              <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground">
                Sign In
              </p>

              {/* Email */}
              <div className="space-y-1.5">
                <Label htmlFor="signin-email" className="text-sm">Email Address</Label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    id="signin-email"
                    type="email"
                    placeholder="you@example.com"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="pl-9 h-9 text-sm"
                    required
                  />
                </div>
              </div>

              {/* Password */}
              <div className="space-y-1.5">
                <div className="flex items-center justify-between">
                  <Label htmlFor="signin-password" className="text-sm">Password</Label>
                  <Link
                    href="/forgot-password"
                    className="text-xs text-primary hover:underline"
                  >
                    Forgot password?
                  </Link>
                </div>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    id="signin-password"
                    type={showPassword ? "text" : "password"}
                    placeholder="••••••••"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="pl-9 pr-10 h-9 text-sm"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword((p) => !p)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                    aria-label={showPassword ? "Hide password" : "Show password"}
                  >
                    {showPassword ? <EyeOff className="h-3.5 w-3.5" /> : <Eye className="h-3.5 w-3.5" />}
                  </button>
                </div>
              </div>
            </div>

            {/* Submit */}
            <Button
              type="submit"
              className="w-full h-10 gradient-primary border-0 font-semibold text-sm"
              disabled={isLoading}
            >
              {isLoading ? "Signing in…" : (
                <>
                  Sign In
                  <ArrowRight className="ml-2 h-4 w-4" />
                </>
              )}
            </Button>

            {/* ── Demo Access Section ── */}
            <div className="rounded-xl border bg-card p-5 space-y-3">
              <div className="flex items-center gap-2">
                <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground">
                  Try a demo
                </p>
                <div className="flex-1 h-px bg-border" />
              </div>

              <p className="text-xs text-muted-foreground">
                Explore CareConnect without creating an account.
              </p>

              <div className="grid grid-cols-3 gap-2">
                {demoRoles.map(({ role, label, icon, description }) => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => handleDemoLogin(role)}
                    disabled={isLoading}
                    className={cn(
                      "flex flex-col items-center gap-2 rounded-lg border bg-background p-3",
                      "text-center transition-all hover:border-primary/50 hover:bg-primary/5",
                      "disabled:opacity-50 disabled:cursor-not-allowed",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                    )}
                  >
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-muted text-muted-foreground">
                      {icon}
                    </div>
                    <div>
                      <p className="text-xs font-semibold text-foreground leading-tight">{label}</p>
                      <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <p className="text-center text-xs text-muted-foreground pb-2">
              By signing in you agree to our{" "}
              <span className="text-primary cursor-pointer hover:underline">Terms</span> &amp;{" "}
              <span className="text-primary cursor-pointer hover:underline">Privacy Policy</span>.
            </p>

          </form>
        </motion.div>
      </div>

    </div>
  );
}